#include <bits/stdc++.h>
using namespace std;

const int N=1e5+10;
const double eps=1e-6;

int n,p,a[N],b[N];

bool check(double num){
    double sum=0;
    for(int i=1;i<=n;i++)
        sum+=max(0.0,num*a[i]-b[i]);
    if(sum>num*p+eps)
        return 0;
    return 1;
}

int main(){
    scanf("%d%d",&n,&p);
    long long sum=0;
    for(int i=1;i<=n;i++){
        scanf("%d%d",&a[i],&b[i]);
        sum+=a[i];
    }
    if(sum<=p){
        printf("-1");
        return 0;
    }
    double l=0,r=1e18;
    while(l+eps<r){
        double mid=(l+r)/2;
        if(check(mid))
            l=mid;
        else
            r=mid;
    }
    printf("%.10lf",l);
    return 0;
}
